messages.content:
You are a real-time systems architect specializing in WebSocket APIs.

Given this requirement:
- ID: WA-PROF-003
- Title: Info/Status Text
- Description: Das System MUSS einen kurzen Info-Text im Profil unterstuetzen

Derive WebSocket channels and events needed for real-time features.

Return JSON format:
{
    "channels": [
        {
            "name": "chat/messages",
            "description": "Real-time chat message delivery",
            "subscribe": {
                "name": "ChatMessageReceived",
                "description": "Incoming message from another user",
                "fields": {
                    "message_id": {"type": "string", "description": "Unique message ID"},
                    "sender_id": {"type": "string", "description": "Sender user ID"},
                    "content": {"type": "string", "description": "Message content"},
                    "timestamp": {"type": "string", "format": "date-time"}
                }
            },
            "publish": {
                "name": "SendChatMessage",
                "description": "Send a new message",
                "fields": {
                    "conversation_id": {"type": "string"},
                    "content": {"type": "string"},
                    "type": {"type": "string", "enum": ["text", "image", "file"]}
                }
            },
            "parameters": {
                "conversation_id": "string"
            }
        }
    ]
}

Guidelines:
- Use hierarchical channel names (e.g., "chat/messages", "user/presence", "call/signal")
- subscribe = events FROM server TO client (receiving)
- publish = events FROM client TO server (sending)
- Include all necessary fields with types
- Consider acknowledgment events where needed
- Only include channels directly related to the requirement

Return ONLY valid JSON.

{
  "channels": [
    {
      "name": "profile/status",
      "description": "Real-time profile info/status text updates",
      "subscribe": {
        "name": "ProfileStatusUpdated",
        "description": "Notifies clients when a user's profile status text changes",
        "fields": {
          "user_id": {"type": "string", "description": "User whose status was updated"},
          "status_text": {"type": "string", "description": "New status text"},
          "updated_at": {"type": "string", "format": "date-time", "description": "Update timestamp"}
        }
      },
      "publish": {
        "name": "UpdateProfileStatus",
        "description": "Update the authenticated user's profile status text",
        "fields": {
          "status_text": {"type": "string", "description": "New status text"}
        }
      },
      "parameters": {
        "user_id": "string"
      }
    },
    {
      "name": "profile/status/ack",
      "description": "Acknowledgment for status text updates",
      "subscribe": {
        "name": "ProfileStatusUpdateAck",
        "description": "Acknowledges a profile status update request",
        "fields": {
          "request_id": {"type": "string", "description": "Client-generated request ID"},
          "success": {"type": "boolean"},
          "error_code": {"type": "string", "nullable": true},
          "error_message": {"type": "string", "nullable": true},
          "updated_at": {"type": "string", "format": "date-time", "nullable": true}
        }
      },
      "publish": {
        "name": "ProfileStatusUpdateRequest",
        "description": "Client-generated request ID for tracking",
        "fields": {
          "request_id": {"type": "string"},
          "status_text": {"type": "string"}
        }
      }
    }
  ]
}

You are a real-time systems architect specializing in WebSocket APIs.

Given this requirement:
- ID: WA-MSG-001
- Title: Textnachricht senden
- Description: Das System MUSS das Senden von Textnachrichten in Echtzeit ermoeglichen

Derive WebSocket channels and events needed for real-time features.

Return JSON format:
{
    "channels": [
        {
            "name": "chat/messages",
            "description": "Real-time chat message delivery",
            "subscribe": {
                "name": "ChatMessageReceived",
                "description": "Incoming message from another user",
                "fields": {
                    "message_id": {"type": "string", "description": "Unique message ID"},
                    "sender_id": {"type": "string", "description": "Sender user ID"},
                    "content": {"type": "string", "description": "Message content"},
                    "timestamp": {"type": "string", "format": "date-time"}
                }
            },
            "publish": {
                "name": "SendChatMessage",
                "description": "Send a new message",
                "fields": {
                    "conversation_id": {"type": "string"},
                    "content": {"type": "string"},
                    "type": {"type": "string", "enum": ["text", "image", "file"]}
                }
            },
            "parameters": {
                "conversation_id": "string"
            }
        }
    ]
}

Guidelines:
- Use hierarchical channel names (e.g., "chat/messages", "user/presence", "call/signal")
- subscribe = events FROM server TO client (receiving)
- publish = events FROM client TO server (sending)
- Include all necessary fields with types
- Consider acknowledgment events where needed
- Only include channels directly related to the requirement

Return ONLY valid JSON.

{
  "channels": [
    {
      "name": "chat/messages",
      "description": "Real-time text message delivery",
      "parameters": {
        "conversation_id": "string"
      },
      "subscribe": [
        {
          "name": "TextMessageReceived",
          "description": "Incoming text message from another user",
          "fields": {
            "message_id": {
              "type": "string",
              "description": "Unique message ID"
            },
            "conversation_id": {
              "type": "string",
              "description": "Conversation ID"
            },
            "sender_id": {
              "type": "string",
              "description": "Sender user ID"
            },
            "content": {
              "type": "string",
              "description": "Text content"
            },
            "timestamp": {
              "type": "string",
              "format": "date-time",
              "description": "Server timestamp"
            }
          }
        },
        {
          "name": "MessageAck",
          "description": "Acknowledgment of sent text message",
          "fields": {
            "client_message_id": {
              "type": "string",
              "description": "Client-generated temporary ID"
            },
            "message_id": {
              "type": "string",
              "description": "Server-assigned message ID"
            },
            "conversation_id": {
              "type": "string",
              "description": "Conversation ID"
            },
            "status": {
              "type": "string",
              "enum": ["accepted", "rejected"]
            },
            "timestamp": {
              "type": "string",
              "format": "date-time"
            },
            "error": {
              "type": "string",
              "description": "Error reason if rejected"
            }
          }
        }
      ],
      "publish": [
        {
          "name": "SendTextMessage",
          "description": "Send a new text message",
          "fields": {
            "client_message_id": {
              "type": "string",
              "description": "Client-generated temporary ID for deduplication"
            },
            "conversation_id": {
              "type": "string",
              "description": "Conversation ID"
            },
            "content": {
              "type": "string",
              "description": "Text content"
            }
          }
        }
      ]
    }
  ]
}

